class Solution:
    def binaryGap(self, n: int) -> int:
        max_gap = 0
        last_pos = None
        pos = 0
        while n:
            if n & 1:
                if last_pos is not None:
                    max_gap = max(max_gap, pos - last_pos)
                last_pos = pos
            pos += 1
            n >>= 1
        return max_gap

